@page "/board"
@using sv_cf3b0d2770414076b414f5a0a772e558.Components.Board
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Project Board</h3>

@if (loading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger">@errorMessage</div>
}
else
{
    <!-- Stats Bar -->
    <div class="row g-2 mb-3">
        <div class="col"><div class="card text-center p-2"><strong>@allTasks.Count</strong><br/><small>Total</small></div></div>
        <div class="col"><div class="card text-center p-2"><strong>@TodoTasks.Count</strong><br/><small>To Do</small></div></div>
        <div class="col"><div class="card text-center p-2"><strong>@InProgressTasks.Count</strong><br/><small>In Progress</small></div></div>
        <div class="col"><div class="card text-center p-2"><strong>@DoneTasks.Count</strong><br/><small>Done</small></div></div>
        <div class="col"><div class="card text-center p-2 border-danger"><strong class="text-danger">@OverdueCount</strong><br/><small>Overdue</small></div></div>
    </div>

    <!-- Search Bar -->
    <div class="mb-3">
        <input type="text" class="form-control" placeholder="Search tasks by title..."
               @bind="searchTerm" @bind:event="oninput" />
    </div>

    <!-- Kanban Columns -->
    <div class="row g-3">
        <KanbanColumn Title="To Do"
                      Tasks="FilteredTodo"
                      CanMoveLeft="false"
                      CanMoveRight="true"
                      OnMoveRight="(id) => MoveTask(id, \"In Progress\")"
                      OnAddTask="(t) => AddTask(t, \"To Do\")" />

        <KanbanColumn Title="In Progress"
                      Tasks="FilteredInProgress"
                      CanMoveLeft="true"
                      CanMoveRight="true"
                      OnMoveLeft="(id) => MoveTask(id, \"To Do\")"
                      OnMoveRight="(id) => MoveTask(id, \"Done\")"
                      OnAddTask="(t) => AddTask(t, \"In Progress\")" />

        <KanbanColumn Title="Done"
                      Tasks="FilteredDone"
                      CanMoveLeft="true"
                      CanMoveRight="false"
                      OnMoveLeft="(id) => MoveTask(id, \"In Progress\")"
                      OnAddTask="(t) => AddTask(t, \"Done\")" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchTerm = "";
    private bool loading = true;
    private string? errorMessage;

    private List<TaskItem> TodoTasks => allTasks.Where(t => t.Status == "To Do").ToList();
    private List<TaskItem> InProgressTasks => allTasks.Where(t => t.Status == "In Progress").ToList();
    private List<TaskItem> DoneTasks => allTasks.Where(t => t.Status == "Done").ToList();

    private List<TaskItem> FilteredTodo => Filter(TodoTasks);
    private List<TaskItem> FilteredInProgress => Filter(InProgressTasks);
    private List<TaskItem> FilteredDone => Filter(DoneTasks);

    private int OverdueCount => allTasks.Count(t => t.DueDate < DateTime.Today && t.Status != "Done");

    private List<TaskItem> Filter(List<TaskItem> tasks)
    {
        if (string.IsNullOrWhiteSpace(searchTerm))
            return tasks;
        return tasks.Where(t => t.Title.Contains(searchTerm, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    protected override async Task OnInitializedAsync()
    {
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            loading = false;
        }
    }

    private async Task MoveTask(int taskId, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var task = allTasks.First(t => t.Id == taskId);
            allTasks = allTasks.Select(t => t.Id == taskId ? task with { Status = newStatus } : t).ToList();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task AddTask((string Title, string Assignee, string Priority, DateTime DueDate) newTask, string status)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(newTask.Title, newTask.Assignee, newTask.Priority, newTask.DueDate);
            allTasks.Add(created with { Status = status });
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
    }
}

